1	#!/usr/bin/env node
2	/**
3	 * GPT-5 vs Claude — Cai Coaching Tool Call Comparison
4	 * ====================================================
5	 * Runs identical coaching conversations against both models using Cai's actual
6	 * tool schemas (coaching_step, book_session, suggest_replies, get_context),
7	 * then dumps side-by-side markdown transcripts for quality comparison.
8	 *
9	 * Usage:
10	 *   export OPENAI_API_KEY="sk-..."
11	 *   export ANTHROPIC_API_KEY="sk-ant-..."
12	 *   node src/compare.js [--model-gpt <model>] [--model-claude <model>]
13	 */
14	
15	import OpenAI from 'openai';
16	import Anthropic from '@anthropic-ai/sdk';
17	import { writeFileSync, mkdirSync } from 'node:fs';
18	import { join, dirname } from 'node:path';
19	import { fileURLToPath } from 'node:url';
20	
21	import {
22	  OPENAI_TOOLS,
23	  ANTHROPIC_TOOLS,
24	  SYSTEM_PROMPT,
25	  USER_MESSAGES,
26	  getMockToolResponse,
27	  VALID_PHASES,
28	  VALID_SIGNALS,
29	} from './schemas.js';
30	
31	const __dirname = dirname(fileURLToPath(import.meta.url));
32	const PROJECT_ROOT = join(__dirname, '..');
33	
34	// ── CLI args ───────────────────────────────────────────────────────────────
35	
36	function parseArgs() {
37	  const args = process.argv.slice(2);
38	  const config = {
39	    modelGpt: 'gpt-5',
40	    modelClaude: 'claude-sonnet-4-6',
41	  };
42	  for (let i = 0; i < args.length; i++) {
43	    if (args[i] === '--model-gpt' && args[i + 1]) config.modelGpt = args[++i];
44	    if (args[i] === '--model-claude' && args[i + 1]) config.modelClaude = args[++i];
45	  }
46	  return config;
47	}
48	
49	// ── Data structures ────────────────────────────────────────────────────────
50	
51	/**
52	 * @typedef {Object} ToolCallRecord
53	 * @property {string} name
54	 * @property {Object} arguments
55	 * @property {boolean} isValidJson
56	 * @property {string|null} parseError
57	 */
58	
59	/**
60	 * @typedef {Object} TurnRecord
61	 * @property {number} turnIndex - Which user message this corresponds to
62	 * @property {string} userMessage
63	 * @property {string} assistantText
64	 * @property {ToolCallRecord[]} toolCalls
65	 * @property {number} latencyMs
66	 * @property {number} inputTokens
67	 * @property {number} outputTokens
68	 * @property {number} toolLoopRounds - How many API calls for this turn (ideally 2: tool call + text)
69	 * @property {string|null} error
70	 */
71	
72	// ── OpenAI runner (Responses API) ──────────────────────────────────────────
73	
74	async function runOpenAI(userMessages, model) {
75	  const client = new OpenAI();
76	  const turns = [];
77	  const conversationInput = [];
78	
79	  for (let i = 0; i < userMessages.length; i++) {
80	    const userMsg = userMessages[i];
81	    conversationInput.push({ role: 'user', content: userMsg });
82	
83	    const turn = {
84	      turnIndex: i,
85	      userMessage: userMsg,
86	      assistantText: '',
87	      toolCalls: [],
88	      latencyMs: 0,
89	      inputTokens: 0,
90	      outputTokens: 0,
91	      toolLoopRounds: 0,
92	      error: null,
93	    };
94	
95	    // Tool loop: allow up to 4 rounds (tool call + result, possibly repeated)
96	    for (let round = 0; round < 4; round++) {
97	      const t0 = performance.now();
98	      let response;
99	      try {
100	        response = await client.responses.create({
101	          model,
102	          instructions: SYSTEM_PROMPT,
103	          input: conversationInput,
104	          tools: OPENAI_TOOLS,
105	        });
106	      } catch (err) {
107	        turn.error = err.message;
108	        turn.latencyMs += performance.now() - t0;
109	        break;
110	      }
111	      const latency = performance.now() - t0;
112	      turn.latencyMs += latency;
113	      turn.toolLoopRounds++;
114	
115	      // Parse usage
116	      if (response.usage) {
117	        turn.inputTokens += response.usage.input_tokens || 0;
118	        turn.outputTokens += response.usage.output_tokens || 0;
119	      }
120	
121	      // Collect text and tool calls
122	      const textParts = [];
123	      const toolCallsInRound = [];
124	
125	      for (const item of response.output) {
126	        if (item.type === 'message') {
127	          for (const content of item.content) {
128	            if (content.text) textParts.push(content.text);
129	          }
130	        } else if (item.type === 'function_call') {
131	          let args = {};
132	          let isValid = true;
133	          let parseError = null;
134	          try {
135	            args = typeof item.arguments === 'string'
136	              ? JSON.parse(item.arguments)
137	              : item.arguments || {};
138	          } catch (err) {
139	            isValid = false;
140	            parseError = err.message;
141	          }
142	          toolCallsInRound.push({
143	            item,
144	            record: { name: item.name, arguments: args, isValidJson: isValid, parseError },
145	          });
146	        }
147	      }
148	
149	      if (textParts.length > 0) {
150	        turn.assistantText += (turn.assistantText ? '\n' : '') + textParts.join('\n');
151	      }
152	      turn.toolCalls.push(...toolCallsInRound.map(t => t.record));
153	
154	      // If tool calls were made, feed ALL output items back (including reasoning)
155	      // then append tool results
156	      if (toolCallsInRound.length > 0) {
157	        // Push all output items (reasoning + function_call + message) to preserve context
158	        for (const item of response.output) {
159	          conversationInput.push(item);
160	        }
161	        // Then append tool results for each function call
162	        for (const { item, record } of toolCallsInRound) {
163	          const mockResult = getMockToolResponse(record.name, record.arguments);
164	          conversationInput.push({
165	            type: 'function_call_output',
166	            call_id: item.call_id,
167	            output: JSON.stringify(mockResult),
168	          });
169	        }
170	      } else {
171	        // No tool calls — turn is complete, add to conversation history
172	        for (const item of response.output) {
173	          conversationInput.push(item);
174	        }
175	        break;
176	      }
177	    }
178	
179	    turns.push(turn);
180	  }
181	
182	  return turns;
183	}
184	
185	// ── Anthropic runner (Messages API) ────────────────────────────────────────
186	
187	async function runAnthropic(userMessages, model) {
188	  const client = new Anthropic();
189	  const turns = [];
190	  const conversationMessages = [];
191	
192	  for (let i = 0; i < userMessages.length; i++) {
193	    const userMsg = userMessages[i];
194	    conversationMessages.push({ role: 'user', content: userMsg });
195	
196	    const turn = {
197	      turnIndex: i,
198	      userMessage: userMsg,
199	      assistantText: '',
200	      toolCalls: [],
201	      latencyMs: 0,
202	      inputTokens: 0,
203	      outputTokens: 0,
204	      toolLoopRounds: 0,
205	      error: null,
206	    };
207	
208	    for (let round = 0; round < 4; round++) {
209	      const t0 = performance.now();
210	      let response;
211	      try {
212	        response = await client.messages.create({
213	          model,
214	          max_tokens: 2048,
215	          system: SYSTEM_PROMPT,
216	          messages: conversationMessages,
217	          tools: ANTHROPIC_TOOLS,
218	          temperature: 0.7,
219	        });
220	      } catch (err) {
221	        turn.error = err.message;
222	        turn.latencyMs += performance.now() - t0;
223	        break;
224	      }
225	      const latency = performance.now() - t0;
226	      turn.latencyMs += latency;
227	      turn.toolLoopRounds++;
228	
229	      turn.inputTokens += response.usage.input_tokens;
230	      turn.outputTokens += response.usage.output_tokens;
231	
232	      const textParts = [];
233	      const toolCallsInRound = [];
234	
235	      for (const block of response.content) {
236	        if (block.type === 'text') {
237	          textParts.push(block.text);
238	        } else if (block.type === 'tool_use') {
239	          toolCallsInRound.push({
240	            block,
241	            record: {
242	              name: block.name,
243	              arguments: typeof block.input === 'object' ? block.input : {},
244	              isValidJson: true,
245	              parseError: null,
246	            },
247	          });
248	        }
249	      }
250	
251	      if (textParts.length > 0) {
252	        turn.assistantText += (turn.assistantText ? '\n' : '') + textParts.join('\n');
253	      }
254	      turn.toolCalls.push(...toolCallsInRound.map(t => t.record));
255	
256	      if (toolCallsInRound.length > 0 && response.stop_reason === 'tool_use') {
257	        // Feed tool results back
258	        conversationMessages.push({ role: 'assistant', content: response.content });
259	        const toolResults = toolCallsInRound.map(({ block, record }) => ({
260	          type: 'tool_result',
261	          tool_use_id: block.id,
262	          content: JSON.stringify(getMockToolResponse(record.name, record.arguments)),
263	        }));
264	        conversationMessages.push({ role: 'user', content: toolResults });
265	      } else {
266	        // Done — add to conversation for next turn
267	        conversationMessages.push({ role: 'assistant', content: response.content });
268	        break;
269	      }
270	    }
271	
272	    turns.push(turn);
273	  }
274	
275	  return turns;
276	}
277	
278	// ── Evaluation ─────────────────────────────────────────────────────────────
279	
280	function evaluate(turns, modelName) {
281	  const scores = {
282	    model: modelName,
283	    totalTurns: turns.length,
284	    coachingStepCalls: 0,
285	    turnsWithCoachingStep: 0,
286	    turnsWithoutCoachingStep: 0,
287	    validPhases: 0,
288	    invalidPhases: [],
289	    signalPresentOnOffer: 0,
290	    offerPhasesTotal: 0,
291	    themesProvided: 0,
292	    multiToolTurns: 0,
293	    totalToolCalls: 0,
294	    totalLatencyMs: 0,
295	    totalInputTokens: 0,
296	    totalOutputTokens: 0,
297	    turnsWithQuestions: 0,
298	    errors: [],
299	    phaseSequence: [],
300	  };
301	
302	  for (const turn of turns) {
303	    if (turn.error) scores.errors.push({ turn: turn.turnIndex, error: turn.error });
304	
305	    scores.totalLatencyMs += turn.latencyMs;
306	    scores.totalInputTokens += turn.inputTokens;
307	    scores.totalOutputTokens += turn.outputTokens;
308	    scores.totalToolCalls += turn.toolCalls.length;
309	
310	    // Count coaching_step calls
311	    const coachingSteps = turn.toolCalls.filter(tc => tc.name === 'coaching_step');
312	    scores.coachingStepCalls += coachingSteps.length;
313	
314	    if (coachingSteps.length > 0) {
315	      scores.turnsWithCoachingStep++;
316	    } else {
317	      scores.turnsWithoutCoachingStep++;
318	    }
319	
320	    // Multi-tool check: coaching_step should be the only tool (or paired with suggest_replies)
321	    const nonReplyTools = turn.toolCalls.filter(tc => tc.name !== 'suggest_replies');
322	    if (nonReplyTools.length > 1) {
323	      scores.multiToolTurns++;
324	    }
325	
326	    // Validate coaching_step fields
327	    for (const step of coachingSteps) {
328	      const phase = step.arguments?.phase;
329	      if (VALID_PHASES.includes(phase)) {
330	        scores.validPhases++;
331	        scores.phaseSequence.push(phase);
332	      } else {
333	        scores.invalidPhases.push({ turn: turn.turnIndex, phase });
334	      }
335	
336	      if (phase === 'offer') {
337	        scores.offerPhasesTotal++;
338	        if (step.arguments?.signal && VALID_SIGNALS.includes(step.arguments.signal)) {
339	          scores.signalPresentOnOffer++;
340	        }
341	      }
342	
343	      if (step.arguments?.theme) {
344	        scores.themesProvided++;
345	      }
346	    }
347	
348	    // Coaching tone: does the response contain a question?
349	    if (turn.assistantText.includes('?')) {
350	      scores.turnsWithQuestions++;
351	    }
352	  }
353	
354	  return scores;
355	}
356	
357	// ── Markdown transcript ────────────────────────────────────────────────────
358	
359	function generateMarkdown(gptTurns, claudeTurns, gptScores, claudeScores, config) {
360	  const lines = [];
361	  lines.push('# GPT-5 vs Claude: Coaching Tool Call Comparison');
362	  lines.push('');
363	  lines.push(`**Date:** ${new Date().toISOString().slice(0, 10)}`);
364	  lines.push(`**GPT model:** ${config.modelGpt}`);
365	  lines.push(`**Claude model:** ${config.modelClaude}`);
366	  lines.push(`**Turns:** ${USER_MESSAGES.length}`);
367	  lines.push('');
368	
369	  // Side-by-side turns
370	  for (let i = 0; i < USER_MESSAGES.length; i++) {
371	    lines.push(`## Turn ${i + 1}`);
372	    lines.push('');
373	    lines.push(`**User:** ${USER_MESSAGES[i]}`);
374	    lines.push('');
375	
376	    for (const [label, turns] of [['GPT-5', gptTurns], ['Claude', claudeTurns]]) {
377	      const turn = turns[i];
378	      lines.push(`### ${label}`);
379	      lines.push('');
380	
381	      if (turn?.error) {
382	        lines.push(`> **ERROR:** ${turn.error}`);
383	        lines.push('');
384	        continue;
385	      }
386	
387	      if (turn?.toolCalls.length > 0) {
388	        for (const tc of turn.toolCalls) {
389	          lines.push(`**Tool call:** \`${tc.name}\``);
390	          if (tc.name === 'coaching_step') {
391	            const a = tc.arguments;
392	            lines.push(`- **phase:** \`${a.phase || '(missing)'}\``);
393	            if (a.signal) lines.push(`- **signal:** \`${a.signal}\``);
394	            if (a.theme) lines.push(`- **theme:** \`${a.theme}\``);
395	            if (a.note) lines.push(`- **note:** ${a.note}`);
396	            if (a.replies) lines.push(`- **replies:** ${JSON.stringify(a.replies)}`);
397	            if (a.parked_topics) lines.push(`- **parked_topics:** ${JSON.stringify(a.parked_topics)}`);
398	          } else {
399	            lines.push(`\`\`\`json`);
400	            lines.push(JSON.stringify(tc.arguments, null, 2));
401	            lines.push(`\`\`\``);
402	          }
403	          lines.push('');
404	        }
405	      }
406	
407	      if (turn?.assistantText) {
408	        lines.push(`**Response:**`);
409	        lines.push('');
410	        lines.push(`> ${turn.assistantText.replace(/\n/g, '\n> ')}`);
411	        lines.push('');
412	      }
413	
414	      lines.push(`*Latency: ${turn?.latencyMs?.toFixed(0) || '?'}ms | Tokens: ${turn?.inputTokens || 0}in/${turn?.outputTokens || 0}out | Tool loop rounds: ${turn?.toolLoopRounds || 0}*`);
415	      lines.push('');
416	    }
417	
418	    lines.push('---');
419	    lines.push('');
420	  }
421	
422	  // Evaluation summary
423	  lines.push('## Evaluation Summary');
424	  lines.push('');
425	  lines.push('| Metric | GPT-5 | Claude |');
426	  lines.push('|--------|-------|--------|');
427	
428	  const metrics = [
429	    ['coaching_step calls', s => s.coachingStepCalls],
430	    ['Turns with coaching_step', s => `${s.turnsWithCoachingStep}/${s.totalTurns}`],
431	    ['Valid phase values', s => `${s.validPhases}/${s.coachingStepCalls}`],
432	    ['Invalid phases', s => s.invalidPhases.length > 0 ? s.invalidPhases.map(p => p.phase).join(', ') : 'None'],
433	    ['Signal on offer phase', s => `${s.signalPresentOnOffer}/${s.offerPhasesTotal}`],
434	    ['Themes provided', s => `${s.themesProvided}/${s.coachingStepCalls}`],
435	    ['Multi-tool turns (violation)', s => s.multiToolTurns],
436	    ['Phase sequence', s => s.phaseSequence.join(' → ')],
437	    ['Turns with questions', s => `${s.turnsWithQuestions}/${s.totalTurns}`],
438	    ['Total tool calls', s => s.totalToolCalls],
439	    ['Total latency', s => `${s.totalLatencyMs.toFixed(0)}ms`],
440	    ['Total input tokens', s => s.totalInputTokens],
441	    ['Total output tokens', s => s.totalOutputTokens],
442	    ['Errors', s => s.errors.length > 0 ? s.errors.map(e => e.error).join('; ') : 'None'],
443	  ];
444	
445	  for (const [label, fn] of metrics) {
446	    lines.push(`| ${label} | ${fn(gptScores)} | ${fn(claudeScores)} |`);
447	  }
448	
449	  lines.push('');
450	  return lines.join('\n');
451	}
452	
453	// ── Console output ─────────────────────────────────────────────────────────
454	
455	function printSummary(label, scores) {
456	  console.log(`\n--- ${label} (${scores.model}) ---`);
457	  console.log(`  coaching_step calls:    ${scores.coachingStepCalls} (${scores.turnsWithCoachingStep}/${scores.totalTurns} turns)`);
458	  console.log(`  Valid phases:           ${scores.validPhases}/${scores.coachingStepCalls}`);
459	  console.log(`  Phase sequence:         ${scores.phaseSequence.join(' → ')}`);
460	  console.log(`  Signal on offer:        ${scores.signalPresentOnOffer}/${scores.offerPhasesTotal}`);
461	  console.log(`  Themes provided:        ${scores.themesProvided}/${scores.coachingStepCalls}`);
462	  console.log(`  Multi-tool violations:  ${scores.multiToolTurns}`);
463	  console.log(`  Turns with questions:   ${scores.turnsWithQuestions}/${scores.totalTurns}`);
464	  console.log(`  Total latency:          ${scores.totalLatencyMs.toFixed(0)}ms`);
465	  console.log(`  Tokens (in/out):        ${scores.totalInputTokens}/${scores.totalOutputTokens}`);
466	  if (scores.errors.length > 0) {
467	    console.log(`  ERRORS:                 ${scores.errors.map(e => `Turn ${e.turn}: ${e.error}`).join('; ')}`);
468	  }
469	}
470	
471	// ── Main ───────────────────────────────────────────────────────────────────
472	
473	async function main() {
474	  const config = parseArgs();
475	
476	  if (!process.env.OPENAI_API_KEY) {
477	    console.error('ERROR: OPENAI_API_KEY environment variable not set');
478	    process.exit(1);
479	  }
480	  if (!process.env.ANTHROPIC_API_KEY) {
481	    console.error('ERROR: ANTHROPIC_API_KEY environment variable not set');
482	    process.exit(1);
483	  }
484	
485	  console.log(`GPT-5 vs Claude Coaching Comparison`);
486	  console.log(`  GPT model:    ${config.modelGpt}`);
487	  console.log(`  Claude model: ${config.modelClaude}`);
488	  console.log(`  Turns:        ${USER_MESSAGES.length}`);
489	  console.log('');
490	
491	  // Run GPT-5
492	  console.log('▶ Running GPT-5 conversation...');
493	  const gptTurns = await runOpenAI(USER_MESSAGES, config.modelGpt);
494	  console.log(`  Done (${gptTurns.length} turns)`);
495	
496	  // Run Claude
497	  console.log('▶ Running Claude conversation...');
498	  const claudeTurns = await runAnthropic(USER_MESSAGES, config.modelClaude);
499	  console.log(`  Done (${claudeTurns.length} turns)`);
500	
501	  // Evaluate
502	  const gptScores = evaluate(gptTurns, config.modelGpt);
503	  const claudeScores = evaluate(claudeTurns, config.modelClaude);
504	
505	  // Print summary
506	  console.log('\n' + '='.repeat(70));
507	  console.log('EVALUATION SUMMARY');
508	  console.log('='.repeat(70));
509	  printSummary('GPT-5', gptScores);
510	  printSummary('Claude', claudeScores);
511	
512	  // Write markdown transcript
513	  const outputDir = join(PROJECT_ROOT, 'output');
514	  mkdirSync(outputDir, { recursive: true });
515	
516	  const markdown = generateMarkdown(gptTurns, claudeTurns, gptScores, claudeScores, config);
517	  const mdPath = join(outputDir, 'transcript.md');
518	  writeFileSync(mdPath, markdown);
519	  console.log(`\nMarkdown transcript: ${mdPath}`);
520	
521	  // Write raw JSON
522	  const jsonPath = join(outputDir, 'results.json');
523	  writeFileSync(jsonPath, JSON.stringify({ config, gpt: gptTurns, claude: claudeTurns, gptScores, claudeScores }, null, 2));
524	  console.log(`Raw results:         ${jsonPath}`);
525	}
526	
527	main().catch(err => {
528	  console.error('Fatal error:', err);
529	  process.exit(1);
530	});
