#!/usr/bin/env node
/**
 * GPT-5 vs Claude — Cai Coaching Tool Call Comparison
 * ====================================================
 * Runs identical coaching conversations against both models using Cai's actual
 * tool schemas (coaching_step, book_session, suggest_replies, get_context),
 * then dumps side-by-side markdown transcripts for quality comparison.
 *
 * Usage:
 *   export OPENAI_API_KEY="sk-..."
 *   export ANTHROPIC_API_KEY="sk-ant-..."
 *   node src/compare.js [--model-gpt <model>] [--model-claude <model>]
 */

import OpenAI from 'openai';
import Anthropic from '@anthropic-ai/sdk';
import { writeFileSync, mkdirSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

import {
  OPENAI_TOOLS,
  ANTHROPIC_TOOLS,
  SYSTEM_PROMPT,
  USER_MESSAGES,
  getMockToolResponse,
  VALID_PHASES,
  VALID_SIGNALS,
} from './schemas.js';

const __dirname = dirname(fileURLToPath(import.meta.url));
const PROJECT_ROOT = join(__dirname, '..');

// ── CLI args ───────────────────────────────────────────────────────────────

function parseArgs() {
  const args = process.argv.slice(2);
  const config = {
    modelGpt: 'gpt-5',
    modelClaude: 'claude-sonnet-4-6',
  };
  for (let i = 0; i < args.length; i++) {
    if (args[i] === '--model-gpt' && args[i + 1]) config.modelGpt = args[++i];
    if (args[i] === '--model-claude' && args[i + 1]) config.modelClaude = args[++i];
  }
  return config;
}

// ── Data structures ────────────────────────────────────────────────────────

/**
 * @typedef {Object} ToolCallRecord
 * @property {string} name
 * @property {Object} arguments
 * @property {boolean} isValidJson
 * @property {string|null} parseError
 */

/**
 * @typedef {Object} TurnRecord
 * @property {number} turnIndex - Which user message this corresponds to
 * @property {string} userMessage
 * @property {string} assistantText
 * @property {ToolCallRecord[]} toolCalls
 * @property {number} latencyMs
 * @property {number} inputTokens
 * @property {number} outputTokens
 * @property {number} toolLoopRounds - How many API calls for this turn (ideally 2: tool call + text)
 * @property {string|null} error
 */

// ── OpenAI runner (Responses API) ──────────────────────────────────────────

async function runOpenAI(userMessages, model) {
  const client = new OpenAI();
  const turns = [];
  const conversationInput = [];

  for (let i = 0; i < userMessages.length; i++) {
    const userMsg = userMessages[i];
    conversationInput.push({ role: 'user', content: userMsg });

    const turn = {
      turnIndex: i,
      userMessage: userMsg,
      assistantText: '',
      toolCalls: [],
      latencyMs: 0,
      inputTokens: 0,
      outputTokens: 0,
      toolLoopRounds: 0,
      error: null,
    };

    // Tool loop: allow up to 4 rounds (tool call + result, possibly repeated)
    for (let round = 0; round < 4; round++) {
      const t0 = performance.now();
      let response;
      try {
        response = await client.responses.create({
          model,
          instructions: SYSTEM_PROMPT,
          input: conversationInput,
          tools: OPENAI_TOOLS,
        });
      } catch (err) {
        turn.error = err.message;
        turn.latencyMs += performance.now() - t0;
        break;
      }
      const latency = performance.now() - t0;
      turn.latencyMs += latency;
      turn.toolLoopRounds++;

      // Parse usage
      if (response.usage) {
        turn.inputTokens += response.usage.input_tokens || 0;
        turn.outputTokens += response.usage.output_tokens || 0;
      }

      // Collect text and tool calls
      const textParts = [];
      const toolCallsInRound = [];

      for (const item of response.output) {
        if (item.type === 'message') {
          for (const content of item.content) {
            if (content.text) textParts.push(content.text);
          }
        } else if (item.type === 'function_call') {
          let args = {};
          let isValid = true;
          let parseError = null;
          try {
            args = typeof item.arguments === 'string'
              ? JSON.parse(item.arguments)
              : item.arguments || {};
          } catch (err) {
            isValid = false;
            parseError = err.message;
          }
          toolCallsInRound.push({
            item,
            record: { name: item.name, arguments: args, isValidJson: isValid, parseError },
          });
        }
      }

      if (textParts.length > 0) {
        turn.assistantText += (turn.assistantText ? '\n' : '') + textParts.join('\n');
      }
      turn.toolCalls.push(...toolCallsInRound.map(t => t.record));

      // If tool calls were made, feed ALL output items back (including reasoning)
      // then append tool results
      if (toolCallsInRound.length > 0) {
        // Push all output items (reasoning + function_call + message) to preserve context
        for (const item of response.output) {
          conversationInput.push(item);
        }
        // Then append tool results for each function call
        for (const { item, record } of toolCallsInRound) {
          const mockResult = getMockToolResponse(record.name, record.arguments);
          conversationInput.push({
            type: 'function_call_output',
            call_id: item.call_id,
            output: JSON.stringify(mockResult),
          });
        }
      } else {
        // No tool calls — turn is complete, add to conversation history
        for (const item of response.output) {
          conversationInput.push(item);
        }
        break;
      }
    }

    turns.push(turn);
  }

  return turns;
}

// ── Anthropic runner (Messages API) ────────────────────────────────────────

async function runAnthropic(userMessages, model) {
  const client = new Anthropic();
  const turns = [];
  const conversationMessages = [];

  for (let i = 0; i < userMessages.length; i++) {
    const userMsg = userMessages[i];
    conversationMessages.push({ role: 'user', content: userMsg });

    const turn = {
      turnIndex: i,
      userMessage: userMsg,
      assistantText: '',
      toolCalls: [],
      latencyMs: 0,
      inputTokens: 0,
      outputTokens: 0,
      toolLoopRounds: 0,
      error: null,
    };

    for (let round = 0; round < 4; round++) {
      const t0 = performance.now();
      let response;
      try {
        response = await client.messages.create({
          model,
          max_tokens: 2048,
          system: SYSTEM_PROMPT,
          messages: conversationMessages,
          tools: ANTHROPIC_TOOLS,
          temperature: 0.7,
        });
      } catch (err) {
        turn.error = err.message;
        turn.latencyMs += performance.now() - t0;
        break;
      }
      const latency = performance.now() - t0;
      turn.latencyMs += latency;
      turn.toolLoopRounds++;

      turn.inputTokens += response.usage.input_tokens;
      turn.outputTokens += response.usage.output_tokens;

      const textParts = [];
      const toolCallsInRound = [];

      for (const block of response.content) {
        if (block.type === 'text') {
          textParts.push(block.text);
        } else if (block.type === 'tool_use') {
          toolCallsInRound.push({
            block,
            record: {
              name: block.name,
              arguments: typeof block.input === 'object' ? block.input : {},
              isValidJson: true,
              parseError: null,
            },
          });
        }
      }

      if (textParts.length > 0) {
        turn.assistantText += (turn.assistantText ? '\n' : '') + textParts.join('\n');
      }
      turn.toolCalls.push(...toolCallsInRound.map(t => t.record));

      if (toolCallsInRound.length > 0 && response.stop_reason === 'tool_use') {
        // Feed tool results back
        conversationMessages.push({ role: 'assistant', content: response.content });
        const toolResults = toolCallsInRound.map(({ block, record }) => ({
          type: 'tool_result',
          tool_use_id: block.id,
          content: JSON.stringify(getMockToolResponse(record.name, record.arguments)),
        }));
        conversationMessages.push({ role: 'user', content: toolResults });
      } else {
        // Done — add to conversation for next turn
        conversationMessages.push({ role: 'assistant', content: response.content });
        break;
      }
    }

    turns.push(turn);
  }

  return turns;
}

// ── Evaluation ─────────────────────────────────────────────────────────────

function evaluate(turns, modelName) {
  const scores = {
    model: modelName,
    totalTurns: turns.length,
    coachingStepCalls: 0,
    turnsWithCoachingStep: 0,
    turnsWithoutCoachingStep: 0,
    validPhases: 0,
    invalidPhases: [],
    signalPresentOnOffer: 0,
    offerPhasesTotal: 0,
    themesProvided: 0,
    multiToolTurns: 0,
    totalToolCalls: 0,
    totalLatencyMs: 0,
    totalInputTokens: 0,
    totalOutputTokens: 0,
    turnsWithQuestions: 0,
    errors: [],
    phaseSequence: [],
  };

  for (const turn of turns) {
    if (turn.error) scores.errors.push({ turn: turn.turnIndex, error: turn.error });

    scores.totalLatencyMs += turn.latencyMs;
    scores.totalInputTokens += turn.inputTokens;
    scores.totalOutputTokens += turn.outputTokens;
    scores.totalToolCalls += turn.toolCalls.length;

    // Count coaching_step calls
    const coachingSteps = turn.toolCalls.filter(tc => tc.name === 'coaching_step');
    scores.coachingStepCalls += coachingSteps.length;

    if (coachingSteps.length > 0) {
      scores.turnsWithCoachingStep++;
    } else {
      scores.turnsWithoutCoachingStep++;
    }

    // Multi-tool check: coaching_step should be the only tool (or paired with suggest_replies)
    const nonReplyTools = turn.toolCalls.filter(tc => tc.name !== 'suggest_replies');
    if (nonReplyTools.length > 1) {
      scores.multiToolTurns++;
    }

    // Validate coaching_step fields
    for (const step of coachingSteps) {
      const phase = step.arguments?.phase;
      if (VALID_PHASES.includes(phase)) {
        scores.validPhases++;
        scores.phaseSequence.push(phase);
      } else {
        scores.invalidPhases.push({ turn: turn.turnIndex, phase });
      }

      if (phase === 'offer') {
        scores.offerPhasesTotal++;
        if (step.arguments?.signal && VALID_SIGNALS.includes(step.arguments.signal)) {
          scores.signalPresentOnOffer++;
        }
      }

      if (step.arguments?.theme) {
        scores.themesProvided++;
      }
    }

    // Coaching tone: does the response contain a question?
    if (turn.assistantText.includes('?')) {
      scores.turnsWithQuestions++;
    }
  }

  return scores;
}

// ── Markdown transcript ────────────────────────────────────────────────────

function generateMarkdown(gptTurns, claudeTurns, gptScores, claudeScores, config) {
  const lines = [];
  lines.push('# GPT-5 vs Claude: Coaching Tool Call Comparison');
  lines.push('');
  lines.push(`**Date:** ${new Date().toISOString().slice(0, 10)}`);
  lines.push(`**GPT model:** ${config.modelGpt}`);
  lines.push(`**Claude model:** ${config.modelClaude}`);
  lines.push(`**Turns:** ${USER_MESSAGES.length}`);
  lines.push('');

  // Side-by-side turns
  for (let i = 0; i < USER_MESSAGES.length; i++) {
    lines.push(`## Turn ${i + 1}`);
    lines.push('');
    lines.push(`**User:** ${USER_MESSAGES[i]}`);
    lines.push('');

    for (const [label, turns] of [['GPT-5', gptTurns], ['Claude', claudeTurns]]) {
      const turn = turns[i];
      lines.push(`### ${label}`);
      lines.push('');

      if (turn?.error) {
        lines.push(`> **ERROR:** ${turn.error}`);
        lines.push('');
        continue;
      }

      if (turn?.toolCalls.length > 0) {
        for (const tc of turn.toolCalls) {
          lines.push(`**Tool call:** \`${tc.name}\``);
          if (tc.name === 'coaching_step') {
            const a = tc.arguments;
            lines.push(`- **phase:** \`${a.phase || '(missing)'}\``);
            if (a.signal) lines.push(`- **signal:** \`${a.signal}\``);
            if (a.theme) lines.push(`- **theme:** \`${a.theme}\``);
            if (a.note) lines.push(`- **note:** ${a.note}`);
            if (a.replies) lines.push(`- **replies:** ${JSON.stringify(a.replies)}`);
            if (a.parked_topics) lines.push(`- **parked_topics:** ${JSON.stringify(a.parked_topics)}`);
          } else {
            lines.push(`\`\`\`json`);
            lines.push(JSON.stringify(tc.arguments, null, 2));
            lines.push(`\`\`\``);
          }
          lines.push('');
        }
      }

      if (turn?.assistantText) {
        lines.push(`**Response:**`);
        lines.push('');
        lines.push(`> ${turn.assistantText.replace(/\n/g, '\n> ')}`);
        lines.push('');
      }

      lines.push(`*Latency: ${turn?.latencyMs?.toFixed(0) || '?'}ms | Tokens: ${turn?.inputTokens || 0}in/${turn?.outputTokens || 0}out | Tool loop rounds: ${turn?.toolLoopRounds || 0}*`);
      lines.push('');
    }

    lines.push('---');
    lines.push('');
  }

  // Evaluation summary
  lines.push('## Evaluation Summary');
  lines.push('');
  lines.push('| Metric | GPT-5 | Claude |');
  lines.push('|--------|-------|--------|');

  const metrics = [
    ['coaching_step calls', s => s.coachingStepCalls],
    ['Turns with coaching_step', s => `${s.turnsWithCoachingStep}/${s.totalTurns}`],
    ['Valid phase values', s => `${s.validPhases}/${s.coachingStepCalls}`],
    ['Invalid phases', s => s.invalidPhases.length > 0 ? s.invalidPhases.map(p => p.phase).join(', ') : 'None'],
    ['Signal on offer phase', s => `${s.signalPresentOnOffer}/${s.offerPhasesTotal}`],
    ['Themes provided', s => `${s.themesProvided}/${s.coachingStepCalls}`],
    ['Multi-tool turns (violation)', s => s.multiToolTurns],
    ['Phase sequence', s => s.phaseSequence.join(' → ')],
    ['Turns with questions', s => `${s.turnsWithQuestions}/${s.totalTurns}`],
    ['Total tool calls', s => s.totalToolCalls],
    ['Total latency', s => `${s.totalLatencyMs.toFixed(0)}ms`],
    ['Total input tokens', s => s.totalInputTokens],
    ['Total output tokens', s => s.totalOutputTokens],
    ['Errors', s => s.errors.length > 0 ? s.errors.map(e => e.error).join('; ') : 'None'],
  ];

  for (const [label, fn] of metrics) {
    lines.push(`| ${label} | ${fn(gptScores)} | ${fn(claudeScores)} |`);
  }

  lines.push('');
  return lines.join('\n');
}

// ── Console output ─────────────────────────────────────────────────────────

function printSummary(label, scores) {
  console.log(`\n--- ${label} (${scores.model}) ---`);
  console.log(`  coaching_step calls:    ${scores.coachingStepCalls} (${scores.turnsWithCoachingStep}/${scores.totalTurns} turns)`);
  console.log(`  Valid phases:           ${scores.validPhases}/${scores.coachingStepCalls}`);
  console.log(`  Phase sequence:         ${scores.phaseSequence.join(' → ')}`);
  console.log(`  Signal on offer:        ${scores.signalPresentOnOffer}/${scores.offerPhasesTotal}`);
  console.log(`  Themes provided:        ${scores.themesProvided}/${scores.coachingStepCalls}`);
  console.log(`  Multi-tool violations:  ${scores.multiToolTurns}`);
  console.log(`  Turns with questions:   ${scores.turnsWithQuestions}/${scores.totalTurns}`);
  console.log(`  Total latency:          ${scores.totalLatencyMs.toFixed(0)}ms`);
  console.log(`  Tokens (in/out):        ${scores.totalInputTokens}/${scores.totalOutputTokens}`);
  if (scores.errors.length > 0) {
    console.log(`  ERRORS:                 ${scores.errors.map(e => `Turn ${e.turn}: ${e.error}`).join('; ')}`);
  }
}

// ── Main ───────────────────────────────────────────────────────────────────

async function main() {
  const config = parseArgs();

  if (!process.env.OPENAI_API_KEY) {
    console.error('ERROR: OPENAI_API_KEY environment variable not set');
    process.exit(1);
  }
  if (!process.env.ANTHROPIC_API_KEY) {
    console.error('ERROR: ANTHROPIC_API_KEY environment variable not set');
    process.exit(1);
  }

  console.log(`GPT-5 vs Claude Coaching Comparison`);
  console.log(`  GPT model:    ${config.modelGpt}`);
  console.log(`  Claude model: ${config.modelClaude}`);
  console.log(`  Turns:        ${USER_MESSAGES.length}`);
  console.log('');

  // Run GPT-5
  console.log('▶ Running GPT-5 conversation...');
  const gptTurns = await runOpenAI(USER_MESSAGES, config.modelGpt);
  console.log(`  Done (${gptTurns.length} turns)`);

  // Run Claude
  console.log('▶ Running Claude conversation...');
  const claudeTurns = await runAnthropic(USER_MESSAGES, config.modelClaude);
  console.log(`  Done (${claudeTurns.length} turns)`);

  // Evaluate
  const gptScores = evaluate(gptTurns, config.modelGpt);
  const claudeScores = evaluate(claudeTurns, config.modelClaude);

  // Print summary
  console.log('\n' + '='.repeat(70));
  console.log('EVALUATION SUMMARY');
  console.log('='.repeat(70));
  printSummary('GPT-5', gptScores);
  printSummary('Claude', claudeScores);

  // Write markdown transcript
  const outputDir = join(PROJECT_ROOT, 'output');
  mkdirSync(outputDir, { recursive: true });

  const markdown = generateMarkdown(gptTurns, claudeTurns, gptScores, claudeScores, config);
  const mdPath = join(outputDir, 'transcript.md');
  writeFileSync(mdPath, markdown);
  console.log(`\nMarkdown transcript: ${mdPath}`);

  // Write raw JSON
  const jsonPath = join(outputDir, 'results.json');
  writeFileSync(jsonPath, JSON.stringify({ config, gpt: gptTurns, claude: claudeTurns, gptScores, claudeScores }, null, 2));
  console.log(`Raw results:         ${jsonPath}`);
}

main().catch(err => {
  console.error('Fatal error:', err);
  process.exit(1);
});
